#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int page;
    int counter; // Timestamp of last use
} Frame;

int find_lru(Frame frames[], int num_frames, int current_time) {
    int lru = 0;
    int min_time = frames[0].counter;
    for (int i = 1; i < num_frames; i++) {
        if (frames[i].counter < min_time) {
            min_time = frames[i].counter;
            lru = i;
        }
    }
    return lru;
}

int lru_page_replacement(int pages[], int n, int num_frames) {
    Frame frames[10];
    int page_faults = 0, time = 0;

    for (int i = 0; i < num_frames; i++) {
        frames[i].page = -1;
        frames[i].counter = 0;
    }

    for (int i = 0; i < n; i++) {
        int page = pages[i];
        int hit = 0;

        // Check if page already in frame
        for (int j = 0; j < num_frames; j++) {
            if (frames[j].page == page) {
                hit = 1;
                frames[j].counter = time++;
                break;
            }
        }

        if (!hit) {
            page_faults++;
            int replace_index = -1;

            // Find empty frame
            for (int j = 0; j < num_frames; j++) {
                if (frames[j].page == -1) {
                    replace_index = j;
                    break;
                }
            }

            // Find LRU frame to replace
            if (replace_index == -1) {
                replace_index = find_lru(frames, num_frames, time);
            }

            frames[replace_index].page = page;
            frames[replace_index].counter = time++;
        }
    }
    return page_faults;
}

