FUNCTION Translate(virtual_address, page_table)
BEGIN
    // Extract page number and offset
    page_number = virtual_address DIV 2^d
    offset = virtual_address MOD 2^d

    // Look up page in page table
    IF page_table[page_number].valid_bit == FALSE
        THEN
            TRAP to Operating System (Page Fault)
            // Handle page fault
            Find free frame
            Read page from disk into frame
            Update page_table[page_number]
            Set valid_bit = TRUE
    END IF

    // Get physical frame number
    frame_number = page_table[page_number].frame_number

    // Construct physical address
    physical_address = frame_number * 2^d + offset

    RETURN physical_address
END

import collections

def simulate_page_replacement(algorithm, pages, frames):
    page_faults = 0
    in_memory = set()

    if algorithm == 'FIFO':
        queue = collections.deque()
        for page in pages:
            if page not in in_memory:
                page_faults += 1
                if len(queue) >= frames:
                    old = queue.popleft()
                    in_memory.remove(old)
                queue.append(page)
                in_memory.add(page)

    elif algorithm == 'LRU':
        access_order = []
        for page in pages:
            if page not in in_memory:
                page_faults += 1
                if len(access_order) >= frames:
                    lru_page = access_order.pop(0)
                    in_memory.remove(lru_page)
                in_memory.add(page)
            # Update access order (most recent at end)
            if page in access_order:
                access_order.remove(page)
            access_order.append(page)

    elif algorithm == 'OPTIMAL':
        # Look ahead to find page not used longest
        future = {i: [] for i in range(frames)}

        for i, page in enumerate(pages):
            if page not in in_memory:
                page_faults += 1
                if len(in_memory) >= frames:
                    # Find page used furthest in future
                    furthest = -1
                    to_remove = None
                    for p in in_memory:
                        # Find next use of page p
                        next_use = float('inf')
                        for j in range(i + 1, len(pages)):
                            if pages[j] == p:
                                next_use = j
                                break
                        if next_use > furthest:
                            furthest = next_use
                            to_remove = p
                    in_memory.remove(to_remove)
                in_memory.add(page)

    return page_faults

# Compare algorithms
pages = [7, 0, 1, 2, 0, 3, 0, 4, 2, 3, 0, 1, 2]
frames = 4

for algo in ['FIFO', 'LRU', 'OPTIMAL']:
    faults = simulate_page_replacement(algo, pages, frames)
    print(f"{algo}: {faults} page faults")
